mapper.select:
select su.chinese_name as studentName,su.seat_no as seatNo, su.class_id as classId, sc.class_name as className,
sc.class_serial_number as classNumber,ur.*
from user_reward ur
LEFT JOIN sys_semester sem ON sem.id = ur.term
left join student_info su on ur.student_id = su.id
left join sys_class sc on su.class_id = sc.id
where ur.deleted = 0 and ur.school_id = #{schoolId}

    and ur.sid = #{sid}


    and ur.term = #{term}


    AND sem.department = #{department}


    and su.chinese_name like CONCAT('%', #{studentName}, '%')


    and ur.type = #{type}


    and su.class_id = #{classId}


    and ur.student_id = #{studentId}


    and ur.is_auto = #{isAuto}


    and ur.auto_type = #{autoType}


    su.class_id in

        #{classId}


order by ur.date desc

SELECT
ur.student_id AS studentId,
SUM(ur.min_reward ) AS minRewardCount,
SUM(ur.mid_reward) AS midRewardCount,
SUM(ur.max_reward) AS maxRewardCount
FROM
user_reward ur
WHERE
ur.type = #{type}

    AND ur.sid = #{sid}

AND ur.school_id = #{schoolId}
AND ur.student_id IN

    #{studentId}


    AND ur.term = #{termId}

AND (
    ur.is_auto = 1
    OR (
        ur.is_auto != 1
        AND EXISTS (
            SELECT 1
            FROM act_approval_instance ai
            WHERE ai.business_id = ur.id AND ai.process_type = 3 AND ai.status = 2
            )
    )
)
GROUP BY ur.student_id

SELECT ur.id AS id, task.id AS taskId, ss.name AS termName, ur.meeting_date AS meetingDate, gg.grade_group_name AS groupName, cla.class_name AS className, stu.chinese_name AS studentName, ur.reward_reason AS rewardReason, ai.`status` AS status, ai.start_time AS startTime, ai.start_user_name AS startUserName FROM act_approval_task task INNER JOIN act_approval_instance ai ON task.instance_id = ai.id AND ai.process_type = 3 INNER JOIN user_reward ur ON ur.id = ai.business_id left join student_info stu on ur.student_id = stu.id left join sys_class cla on cla.id = stu.class_id left join grade_group gg on cla.grade_group = gg.id left join sys_semester ss on ur.term = ss.id WHERE task.deleted = 0 AND task.`status` = 0
AND ur.school_id = #{schoolId}
AND JSON_CONTAINS(task.approver_ids, '#{userId}', '$')
AND ur.sid = #{reqModel.sid}
AND ur.term = #{reqModel.term}
AND ur.type = #{reqModel.type}
AND cla.department = #{reqModel.department}
AND stu.class_id = #{reqModel.classId}
AND (stu.chinese_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.student_no LIKE CONCAT('%', #{reqModel.studentInfo}, '%'))
AND ur.reward_reason LIKE CONCAT('%', #{reqModel.rewardReason}, '%')
AND ur.meeting_date >= #{reqModel.startDate}
AND ur.meeting_date <= #{reqModel.endDate}
ORDER BY ur.id DESC

SELECT ur.id AS id, ai.id AS instanceId, ss.name AS termName, ur.meeting_date AS meetingDate, gg.grade_group_name AS groupName, cla.class_name AS className, stu.chinese_name AS studentName, ur.reward_reason AS rewardReason, ai.`status` AS status, ai.start_time AS startTime, ai.start_user_name AS startUserName FROM act_approval_instance ai INNER JOIN user_reward ur ON ur.id = ai.business_id left join student_info stu on ur.student_id = stu.id left join sys_class cla on cla.id = stu.class_id left join grade_group gg on cla.grade_group = gg.id left join sys_semester ss on ur.term = ss.id
INNER JOIN (SELECT DISTINCT instance_id FROM act_approval_history WHERE operate_user_id = #{userId} ) aah ON ai.id = aah.instance_id
WHERE ai.deleted = 0 AND ai.process_type = 3
AND ur.school_id = #{schoolId}
AND ur.sid = #{reqModel.sid}
AND ur.term = #{reqModel.term}
AND ur.type = #{reqModel.type}
AND cla.department = #{reqModel.department}
AND stu.class_id = #{reqModel.classId}
AND (stu.chinese_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.student_no LIKE CONCAT('%', #{reqModel.studentInfo}, '%'))
AND ur.reward_reason LIKE CONCAT('%', #{reqModel.rewardReason}, '%')
AND ur.meeting_date >= #{reqModel.startDate}
AND ur.meeting_date <= #{reqModel.endDate}
ORDER BY ur.id DESC

SELECT ur.id AS id, ai.id AS instanceId, ss.name AS termName, ur.meeting_date AS meetingDate, gg.grade_group_name AS groupName, cla.class_name AS className, stu.chinese_name AS studentName, ur.reward_reason AS rewardReason, ai.`status` AS status, ai.start_time AS startTime, ai.start_user_id AS startUserId, ai.start_user_name AS startUserName FROM act_approval_instance ai INNER JOIN user_reward ur ON ur.id = ai.business_id left join student_info stu on ur.student_id = stu.id left join sys_class cla on cla.id = stu.class_id left join grade_group gg on cla.grade_group = gg.id left join sys_semester ss on ur.term = ss.id WHERE ai.deleted = 0 AND ai.process_type = 3
AND ur.school_id = #{schoolId}
AND cla.id IN
#{item}
AND ur.sid = #{reqModel.sid}
AND ur.term = #{reqModel.term}
AND ur.type = #{reqModel.type}
AND cla.department = #{reqModel.department}
AND stu.class_id = #{reqModel.classId}
AND ai.`status` = #{reqModel.status}
AND (stu.chinese_name LIKE CONCAT('%', #{reqModel.studentInfo}, '%') OR stu.student_no LIKE CONCAT('%', #{reqModel.studentInfo}, '%'))
AND ur.reward_reason LIKE CONCAT('%', #{reqModel.rewardReason}, '%')
AND ur.meeting_date >= #{reqModel.startDate}
AND ur.meeting_date <= #{reqModel.endDate}
ORDER BY ur.id DESC

SELECT ur.* FROM act_approval_instance ai INNER JOIN user_reward ur ON ur.id = ai.business_id WHERE ai.deleted = 0 AND ai.process_type = 3 and ai.`status` = 2 and ur.deleted = 0 and ur.type = 2 and ur.is_auto = 0
AND ur.student_id IN
#{item}
AND ur.term IN
#{item}
and ur.school_id = #{schoolId}
and ur.meeting_date >= #{startTime}
and #{endTime} >= ur.meeting_date
